import json
want={'doi:10.1016/j.caeai.2025.100476','doi:10.1145/3757409','doi:10.70211/bafr.v1i1.178','doi:10.36948/ijfmr.2024.v06i03.22716'}
seen={}
for line in open('/home/polaris/polaris_project/outputs/acquisition_campaign/fetch_ledger.jsonl'):
    e=json.loads(line)
    if e.get('kind')=='manifestation_fetched' and e['unit'] in want:
        p=e['payload']
        tb=(p.get('text_blob_id') or '').replace('sha256:','')
        # keep the largest text blob per unit
        prev=seen.get(e['unit'])
        if tb and (prev is None or p.get('n_bytes',0)>=prev[1]):
            seen[e['unit']]=(tb,p.get('n_bytes',0),p.get('locator'),p.get('content_type'))
for u,(tb,nb,loc,ct) in seen.items():
    print(u)
    print('  text_blob',tb[:16],'raw_bytes',nb,'ct',ct)
    print('  locator',loc)
"
